import{c as o,Q as a,j as r,m as t}from"./chunks/framework.BA1dEi98.js";const h=JSON.parse('{"title":"API Keys","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api-keys.md","filePath":"guide/api-keys.md","lastUpdated":1779872362000}'),s={name:"guide/api-keys.md"};function i(l,e,n,c,d,p){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h1><p>Some external sources require API keys. All are optional — LibrisLog works out of the box with Open Library.</p><h2 id="google-books-api" tabindex="-1">Google Books API <a class="header-anchor" href="#google-books-api" aria-label="Permalink to &quot;Google Books API&quot;">​</a></h2><p>Enables Google Books as a fallback search source and improves cover resolution.</p><ol><li>Go to the <a href="https://console.cloud.google.com" target="_blank" rel="noreferrer">Google Cloud Console</a></li><li>Create a new project or select an existing one</li><li>Navigate to <strong>APIs &amp; Services</strong> → <strong>Library</strong></li><li>Search for &quot;Books API&quot; and enable it</li><li>Go to <strong>APIs &amp; Services</strong> → <strong>Credentials</strong></li><li>Click <strong>Create Credentials</strong> → <strong>API Key</strong></li><li>Copy the key and set it as <code>GOOGLE_BOOKS_API_KEY</code> in your <code>.env</code></li></ol><blockquote><p><strong>Note</strong>: Google Books API has usage limits. For most personal use, the free tier is sufficient. See <a href="https://developers.google.com/books" target="_blank" rel="noreferrer">Google&#39;s documentation</a> for quota details.</p></blockquote><h2 id="hardcover-api" tabindex="-1">Hardcover API <a class="header-anchor" href="#hardcover-api" aria-label="Permalink to &quot;Hardcover API&quot;">​</a></h2><p>Enables Hardcover.app as an additional search source.</p><ol><li>Sign in to <a href="https://hardcover.app" target="_blank" rel="noreferrer">hardcover.app</a></li><li>Go to your profile → <strong>Settings</strong> → <strong>API</strong></li><li>Create a new API token</li><li>Copy the token and set it as <code>HARDCOVER_APP_API_TOKEN</code> in your <code>.env</code></li></ol>',9)])])}const u=o(s,[["render",i]]);export{h as __pageData,u as default};
